import { z } from 'zod';

const cadastroSchema = z.object({
  nome: z
    .string()
    .min(3, 'Nome deve ter pelo menos 3 caracteres'),
  email: z
    .string()
    .email('Email inválido'),
  senha: z
    .string()
    .min(6, 'Senha deve ter pelo menos 6 caracteres'),
  idade: z
    .number()
    .min(18, 'Deve ser maior de 18 anos')
    .optional()
});

// Zod gera o tipo TypeScript automaticamente!
type CadastroData = z.infer<typeof cadastroSchema>;
// { nome: string; email: string; senha: string; idade?: number }

import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const schema = z.object({
  email: z.string().email('Email inválido'),
  senha: z.string().min(6, 'Mínimo 6 caracteres')
});

type FormData = z.infer<typeof schema>;

function LoginForm() {
  const {
    register,
    handleSubmit,
    formState: { errors }
  } = useForm<FormData>({
    resolver: zodResolver(schema)
  });

  return (
    <form onSubmit={handleSubmit((data) => console.log(data))}>
      <input {...register('email')} placeholder="Email" />
      {errors.email && <span>{errors.email.message}</span>}

      <input type="password" {...register('senha')} placeholder="Senha" />
      {errors.senha && <span>{errors.senha.message}</span>}

      <button type="submit">Entrar</button>
    </form>
  );
}

const senhaSchema = z.object({
  senha: z.string().min(6),
  confirmarSenha: z.string()
}).refine(
  (data) => data.senha === data.confirmarSenha,
  {
    message: 'As senhas não coincidem',
    path: ['confirmarSenha'] // erro aparece no campo correto
  }
);
